import React from "react"
import { Link, graphql } from "gatsby"
import { MDXRenderer } from "gatsby-plugin-mdx"
import Layout from "../../components/Layout"
import FA from "../../components/FA"
import { GatsbyImage, getSrc } from "gatsby-plugin-image"
import { getString } from "../../util"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function PageTemplate({ pageContext: { language }, data: { meta, placeholder, mdx, abridged, pierspectives, dp } }) {

	const cx = classNames.bind(styles);
	const f = mdx.frontmatter

	const metadata = meta.siteMetadata.collections.filter(c => c.collection === "members")[0]

	const SocialLinks = () => (
		<div className={cx("links")}>
			{f.website && <a href={f.website} target="_blank" rel="nofollow noopener noreferrer"><FA icon="home" alt="Website" /></a>}
			{f.email && <a href={`mailto:${f.email}`} target="_blank" rel="nofollow noopener noreferrer"><FA icon="email" alt="Email" /></a>}
			{f.facebook && <a href={f.facebook} target="_blank" rel="nofollow noopener noreferrer"><FA icon="facebook" alt="Facebook" /></a>}
			{f.twitter && <a href={f.twitter} target="_blank" rel="nofollow noopener noreferrer"><FA icon="twitter" alt="Twitter" /></a>}
			{f.linkedin && <a href={f.linkedin} target="_blank" rel="nofollow noopener noreferrer"><FA icon="linkedin" alt="LinkedIn" /></a>}
		</div>
	)

	const image = f.image || placeholder.nodes[0]

	return (
		<Layout
			lang={language}
			mdx={mdx}
			metadata={metadata}
			customTitle={true}
		>
			<div className={cx("grid")}>
				<div className={cx("left")}>
					<div className={cx("profile")}>
						<GatsbyImage image={image.childImageSharp.main} alt={f.title} />
						<span hidden data-typesense-field="img_url">{getSrc(image.childImageSharp.thumbnail)}</span>
					</div>
					<SocialLinks />
				</div>
				<div className={cx("right")}>
					<h1 className={cx("name", "align")} data-typesense-field="title">
						{f.title}
					</h1>
					{language === "th" &&
						<span hidden data-typesense-field="title_alt">{f.memberid}</span>
					}
					<div className={cx("org", "align")}>{getString(f.org, language)}</div>
					<div className={cx("align")}>
						{f.prn_officer &&
							<Link to="/pier-research-network/#prn-officers">
								<span className="blob-small-span right-margin-mobile-center">PRN Officer</span>
							</Link>
						}
						{f.first_visit &&
							<Link to="/visiting-fellows/">
								<span className="blob-small-span right-margin-mobile-center">Visiting Fellow</span>
							</Link>
						}
						{(f.org === "สถาบันวิจัยเศรษฐกิจป๋วย อึ๊งภากรณ์" || f.org === "Puey Ungphakorn Institute for Economic Research") &&
							<Link to="/staff/">
								<span className="blob-small-span right-margin-mobile-center">Staff</span>
							</Link>
						}
					</div>
					<SocialLinks />
					<MDXRenderer>{mdx.body}</MDXRenderer>
					{f.fields &&
						<div>
							<h3>Research Interests</h3>
							<ul>
							{
								f.fields.map((e, i) => 
									<li className={cx("expertise")} key={`field${i}`}>{e}</li>
								)
							}
							</ul>
						</div>
					}
					{dp.nodes.length > 0 &&
						<div>
							<h3>Discussion Paper</h3>
							<ul>
							{
								dp.nodes.map((item, i) =>
									<li key={`abridged${i}`}><Link to={item.fields.slug}>{item.frontmatter.title}</Link></li>
								)
							}
							</ul>
						</div>
					}
					{pierspectives.nodes.length > 0 &&
						<div>
							<h3>PIERspectives</h3>
							<ul>
							{
								pierspectives.nodes.map((item, i) =>
									<li key={`pierspectives${i}`}><Link to={item.fields.slug}>{item.frontmatter.title}</Link></li>
								)
							}
							</ul>
						</div>
					}
					{abridged.nodes.length > 0 &&
						<div>
							<h3>aBRIDGEd</h3>
							<ul>
							{
								abridged.nodes.map((item, i) =>
									<li key={`abridged${i}`}><Link to={item.fields.slug}>{item.frontmatter.title}</Link></li>
								)
							}
							</ul>
						</div>
					}
				</div>
			</div>
		</Layout>
	)
}

export const pageQuery = graphql`
	query MemberQuery($id: String, $memberid: String) {
		meta: site {
			siteMetadata {
				collections {
					collection
					title
					subtitle
					url
					placeholder
				}
			}
		}
		placeholder: allFile(
			filter: {sourceInstanceName: {eq: "images"}, relativeDirectory: {eq: "placeholder"}, name: {eq: "user"}}
		) {
			nodes {
				childImageSharp {
					thumbnail: gatsbyImageData(layout: FIXED, width: 160, height: 160)
					main: gatsbyImageData(layout: CONSTRAINED)
				}
			}
		}
		mdx(id: { eq: $id }) {
			id
			body
			fields {
				slug
			}
			frontmatter {
				memberid
				title
				org
				website
				email
				facebook
				twitter
				linkedin
				fields
				image {
					publicURL
					childImageSharp {
						thumbnail: gatsbyImageData(layout: FIXED, width: 160, height: 160)
						main: gatsbyImageData(layout: CONSTRAINED)
					}
				}
				first_visit
				prn_officer
			}
		}
		dp: allMdx(filter: {fields: {collection: {eq: "dp"}}, frontmatter: {authors: {glob: $memberid}}}) {
			nodes {
				fields {
					slug
				}
				frontmatter {
					title
				}
			}
		}
		pierspectives: allMdx(filter: {fields: {collection: {eq: "pierspectives"}}, frontmatter: {authors: {glob: $memberid}}}) {
			nodes {
				fields {
					slug
				}
				frontmatter {
					title
				}
			}
		}
		abridged: allMdx(filter: {fields: {collection: {eq: "abridged"}}, frontmatter: {authors: {glob: $memberid}}}) {
			nodes {
				fields {
					slug
				}
				frontmatter {
					title
				}
			}
		}
	}
`